const VOID_ELEMENTS=new Set(['area','base','br','col','embed','hr','img','input','link','meta','param','source','track','wbr']);export function tokenize(input,options={}){let pos=0;let ch=input[0]??null;const next=()=>{pos++;ch=input[pos]??null};const peek=(n=1)=>input[pos+n]??null;const readWhile=fn=>{let s='';while(ch!==null&&fn(ch)){s+=ch;next()} return s};const tokens=[];const pushToken=(tok)=>tokens.push(tok);const readUntil=terminatorFn=>{let s='';while(ch!==null&&!terminatorFn(ch)){s+=ch;next()} return s};const readComment=()=>{let value='';value+=ch;next();value+=ch;next();value+=ch;next();value+=ch;next();while(ch!==null){if(ch==='-'&&peek()==='-'&&input[pos+2]==='>'){value+='-->';next();next();next();break} value+=ch;next()} pushToken({type:'comment',value})};const readBang=()=>{let value='';value+=ch;next();value+=ch;next();while(ch!==null){value+=ch;if(ch==='>'){next();break} next()} pushToken({type:'doctype',value})};const readTagDetailed=()=>{const local=[];const pushLocal=(type,value,meta)=>{const tok={type,value};if(meta&&typeof meta==='object'){for(const k in meta)tok[k]=meta[k]} local.push(tok)};let accum='';accum+=ch;next();if(ch==='/'){accum+=ch;next();pushLocal('tagopen','</');const name=readWhile(c=>/[A-Za-z0-9:_-]/.test(c));if(name.length>0)pushLocal('tagname',name)}else{pushLocal('tagopen','<');const name=readWhile(c=>/[A-Za-z0-9:_-]/.test(c));if(name.length>0)pushLocal('tagname',name)} while(ch!==null){if(/\s/.test(ch)){const ws=readWhile(c=>/\s/.test(c));pushLocal('whitespace',ws);continue} if(ch==='/'&&peek()==='>'){const v='/>';next();next();pushLocal('selfclose',v);break} if(ch==='>'){pushLocal('tagclose','>');next();break} if(ch!==null&&ch!=='>'&&ch!=='/'&&ch!=='='&&!/\s/.test(ch)){const name=readWhile(c=>c!==null&&!/[\s=/>]/.test(c));if(name.length>0)pushLocal('attrname',name);if(/\s/.test(ch)){const ws2=readWhile(c=>/\s/.test(c));pushLocal('whitespace',ws2)} if(ch==='='){pushLocal('equals','=');next();if(/\s/.test(ch)){const ws3=readWhile(c=>/\s/.test(c));pushLocal('whitespace',ws3)} if(ch==='"'||ch==="'"){const quote=ch;let val='';val+=ch;next();while(ch!==null){if(ch==='\\'){val+=ch;next();if(ch!==null){val+=ch;next()} continue} if(ch===quote){val+=ch;next();break} val+=ch;next()} pushLocal('attrvalue',val)}else{const valUnq=readWhile(c=>c!==null&&!/[\s>\/]/.test(c));if(valUnq.length>0)pushLocal('attrvalue',valUnq)}} continue} const single=ch;pushLocal('char',single);next()} let tagName=null;let isClosing=!1;let isSelfClosing=!1;if(local.length>0&&local[0].type==='tagopen'&&local[0].value==='</')isClosing=!0;for(let i=0;i<local.length;i++){if(local[i].type==='tagname'){tagName=local[i].value;break}} if(local.length>0){const last=local[local.length-1];if(last.type==='selfclose')isSelfClosing=!0} if(tagName&&!isClosing){const lower=tagName.toLowerCase();if(VOID_ELEMENTS.has(lower)){for(let i=0;i<local.length;i++){if(local[i].type==='tagname'){local[i].isVoid=!0;break}}}} for(const t of local)pushToken(t);return{tagName,isClosing,isSelfClosing}};const readText=()=>{const txt=readWhile(c=>c!=='<');if(txt.length>0)pushToken({type:'text',value:txt})};const readRawElement=(tagNameLower)=>{let content='';while(ch!==null){if(ch==='<'&&peek()==='/'){let i=pos+2;while(input[i]!==undefined&&/\s/.test(input[i]))i++;let cand='';while(input[i]!==undefined&&/[A-Za-z0-9:_-]/.test(input[i])){cand+=input[i];i++} if(cand.toLowerCase()===tagNameLower){break}} content+=ch;next()} if(content.length>0){if(options&&typeof options.tokenizeScript==='function'&&(tagNameLower==='script'||tagNameLower==='style')){try{const childTokens=options.tokenizeScript(content);if(Array.isArray(childTokens)&&childTokens.map(t=>t.value).join('')===content){for(const ct of childTokens){const tok={type:ct.type,value:ct.value};pushToken(tok)}}else{pushToken({type:tagNameLower==='script'?'scriptcontent':'stylecontent',value:content})}}catch(e){pushToken({type:tagNameLower==='script'?'scriptcontent':'stylecontent',value:content})}}else{pushToken({type:tagNameLower==='script'?'scriptcontent':'stylecontent',value:content})}}};while(ch!==null){if(ch==='<'){if(input.startsWith('<!--',pos)){readComment();continue} if(ch==='<'&&peek()==='!'){readBang();continue} const beforeLen=tokens.length;const meta=readTagDetailed();if(meta.tagName&&!meta.isClosing){const lower=meta.tagName.toLowerCase();const lastToken=tokens[tokens.length-1];const isSelfClose=lastToken&&lastToken.type==='selfclose';if((lower==='script'||lower==='style')&&!isSelfClose){readRawElement(lower);if(ch==='<'){readTagDetailed()}}} continue} readText()} return tokens}
